import{_ as s,o as e,c as a,ai as l}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"Vue 面试基础：高频 8 题（偏初级）","description":"","frontmatter":{},"headers":[],"relativePath":"resume/vue-interview.md","filePath":"resume/vue-interview.md"}'),t={name:"resume/vue-interview.md"};function n(o,i,h,r,d,k){return e(),a("div",null,[...i[0]||(i[0]=[l(`<h1 id="vue-面试基础-高频-8-题-偏初级" tabindex="-1">Vue 面试基础：高频 8 题（偏初级） <a class="header-anchor" href="#vue-面试基础-高频-8-题-偏初级" aria-label="Permalink to “Vue 面试基础：高频 8 题（偏初级）”">​</a></h1><blockquote><p>这个小模块主要帮我快速过一遍 <strong>最常见的 Vue 面试题</strong>，不卷源码，重点是会用 + 讲得清楚。</p></blockquote><hr><h2 id="一、vue-高频基础题总表" tabindex="-1">一、Vue 高频基础题总表 <a class="header-anchor" href="#一、vue-高频基础题总表" aria-label="Permalink to “一、Vue 高频基础题总表”">​</a></h2><ol><li><strong>Vue 的响应式原理大概是怎么实现的？（2.x / 3.x）</strong></li><li><strong><code>v-if</code> 和 <code>v-show</code> 有什么区别？实际开发怎么选？</strong></li><li><strong><code>computed</code> 和 <code>watch</code> 有什么区别？分别适合什么场景？</strong></li><li><strong>父子组件是如何通信的？常见几种方式？</strong></li><li><strong><code>v-model</code> 本质是什么？在组件里怎么自定义 <code>v-model</code>？</strong></li><li><strong>在列表渲染中为什么一定要加 <code>key</code>？用索引当 key 有什么问题？</strong></li><li><strong>axios 请求一般放在哪一层？怎么统一处理错误、loading、token？</strong></li><li><strong>前端路由的 hash 模式 和 history 模式 有什么区别？配合后端要注意什么？</strong></li></ol><p>建议：先保证这 8 题你都能<strong>用自己的话讲 2～3 分钟</strong>，再去看更细的语法和生态。</p><hr><h2 id="二、高频问题示例答案-简版" tabindex="-1">二、高频问题示例答案（简版） <a class="header-anchor" href="#二、高频问题示例答案-简版" aria-label="Permalink to “二、高频问题示例答案（简版）”">​</a></h2><h3 id="_1-vue-的响应式原理大概是怎么实现的" tabindex="-1">1. Vue 的响应式原理大概是怎么实现的？ <a class="header-anchor" href="#_1-vue-的响应式原理大概是怎么实现的" aria-label="Permalink to “1. Vue 的响应式原理大概是怎么实现的？”">​</a></h3><p><strong>简短版本（适合初级面试）：</strong></p><ul><li>Vue 2.x 主要是通过 <code>Object.defineProperty</code> 监听数据的 <code>get/set</code>，在 <code>set</code> 的时候触发视图更新。</li><li>Vue 3.x 则是用 <code>Proxy</code> 做数据劫持，可以完美监听新增/删除属性、数组下标等问题，弥补了 2.x 的一些缺陷。</li></ul><p><strong>可以顺带提一句：</strong></p><ul><li>模板里用到的数据，会在依赖收集阶段记录下来，数据变更时，只有依赖了它的那部分组件会重新渲染，而不是整棵树全部刷新。</li></ul><hr><h3 id="_2-v-if-和-v-show-有什么区别-怎么选" tabindex="-1">2. <code>v-if</code> 和 <code>v-show</code> 有什么区别？怎么选？ <a class="header-anchor" href="#_2-v-if-和-v-show-有什么区别-怎么选" aria-label="Permalink to “2. v-if 和 v-show 有什么区别？怎么选？”">​</a></h3><ul><li><strong><code>v-if</code></strong>：条件为 <code>false</code> 时，<strong>组件/DOM 直接不会渲染</strong> 或被销毁；为 <code>true</code> 时才真正创建。适合<strong>很少切换</strong>的场景，比如权限控制、大模块的按需渲染。</li><li><strong><code>v-show</code></strong>：始终会渲染到 DOM，只是通过 <code>display: none</code> 控制显示/隐藏。适合<strong>频繁切换</strong>的场景，比如 tab 切换、小弹窗。</li></ul><p>一句话记忆：<strong>“频繁切换用 v-show，偶尔切换用 v-if”</strong>。</p><hr><h3 id="_3-computed-和-watch-有什么区别" tabindex="-1">3. <code>computed</code> 和 <code>watch</code> 有什么区别？ <a class="header-anchor" href="#_3-computed-和-watch-有什么区别" aria-label="Permalink to “3. computed 和 watch 有什么区别？”">​</a></h3><ul><li><p><strong><code>computed</code>（计算属性）</strong>：</p><ul><li>依赖其它响应式数据，<strong>有缓存</strong>。</li><li>只有当依赖的数据发生变化时才会重新计算。</li><li>适合从已有数据中 <strong>派生出新数据</strong>（比如：全名、过滤后的列表）。</li></ul></li><li><p><strong><code>watch</code>（侦听器）</strong>：</p><ul><li>监听某个数据的变化，<strong>在变化时执行副作用逻辑</strong>。</li><li>适合处理异步请求、手动控制逻辑（例如根据输入框内容去搜索接口）。</li></ul></li></ul><p>一句话区分：<strong>“需要一个新值用 computed，要在值变化时做事用 watch”</strong>。</p><hr><h3 id="_4-父子组件如何通信-最常用的几种" tabindex="-1">4. 父子组件如何通信？（最常用的几种） <a class="header-anchor" href="#_4-父子组件如何通信-最常用的几种" aria-label="Permalink to “4. 父子组件如何通信？（最常用的几种）”">​</a></h3><ul><li>父传子：通过 <strong><code>props</code></strong> 传值。</li><li>子通知父：通过 <strong><code>$emit</code> 触发自定义事件</strong>，父组件在模板上监听。</li><li>兄弟组件/跨多层：可以用 <strong>全局事件总线 / Vuex / Pinia / provide/inject</strong> 等方式（初级面试会提到名字即可）。</li></ul><blockquote><p>面试时可以举一个简单例子：父组件把列表数据传给子组件展示，子组件点击“删除”按钮，通过 <code>$emit(&#39;delete&#39;, id)</code> 通知父组件真正去删数据。</p></blockquote><hr><h3 id="_5-v-model-本质是什么-组件里怎么自定义" tabindex="-1">5. <code>v-model</code> 本质是什么？组件里怎么自定义？ <a class="header-anchor" href="#_5-v-model-本质是什么-组件里怎么自定义" aria-label="Permalink to “5. v-model 本质是什么？组件里怎么自定义？”">​</a></h3><ul><li>在原生表单元素上，<code>v-model</code> 大概相当于：<div class="language-html line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> :value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;msg&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> @input</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;msg = $event.target.value&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>在组件上，Vue 3 里等价于：<div class="language-vue line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Child</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> v-model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 等价于 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Child</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> :</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modelValue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> @</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modelValue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $event</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li>自定义组件想支持 <code>v-model</code>，只需要： <ul><li>接收一个 <code>modelValue</code> 的 <code>prop</code>。</li><li>在内部通过 <code>emit(&#39;update:modelValue&#39;, newVal)</code> 往外抛。</li></ul></li></ul><hr><h3 id="_6-为啥列表渲染一定要加-key-索引用作-key-有什么问题" tabindex="-1">6. 为啥列表渲染一定要加 <code>key</code>？索引用作 key 有什么问题？ <a class="header-anchor" href="#_6-为啥列表渲染一定要加-key-索引用作-key-有什么问题" aria-label="Permalink to “6. 为啥列表渲染一定要加 key？索引用作 key 有什么问题？”">​</a></h3><ul><li><code>key</code> 的主要作用是 <strong>帮助虚拟 DOM 更准确地复用元素</strong>。</li><li>如果不加 <code>key</code> 或用索引当 key，在<strong>插入/删除中间某一项时</strong>，可能会导致： <ul><li>复用错误的 DOM 节点。</li><li>比如输入框错位、动画异常、组件内部状态混乱。</li></ul></li><li>通常建议用 <strong>唯一业务 id 作为 key</strong>。</li></ul><hr><h3 id="_7-axios-一般怎么用-放在哪一层" tabindex="-1">7. axios 一般怎么用？放在哪一层？ <a class="header-anchor" href="#_7-axios-一般怎么用-放在哪一层" aria-label="Permalink to “7. axios 一般怎么用？放在哪一层？”">​</a></h3><ul><li>一般会抽一层 <strong>统一的请求封装</strong>： <ul><li>统一设置 baseURL、超时时间。</li><li>请求拦截里加上 token。</li><li>响应拦截统一处理错误提示、登录失效跳转等。</li></ul></li><li>页面或组件里只调用 <strong>封装好的 API 函数</strong>，例如：<div class="language-ts line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { getUserList } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@/api/user&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> list</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> getUserList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li></ul><blockquote><p>面试时可以简单描述你项目里的封装结构，哪怕是自己练手项目也可以讲清楚“为什么要这么封、怎么封”的思路。</p></blockquote><hr><h3 id="_8-前端路由-hash-模式-vs-history-模式-有什么区别" tabindex="-1">8. 前端路由 hash 模式 vs history 模式 有什么区别？ <a class="header-anchor" href="#_8-前端路由-hash-模式-vs-history-模式-有什么区别" aria-label="Permalink to “8. 前端路由 hash 模式 vs history 模式 有什么区别？”">​</a></h3><ul><li><strong>hash 模式</strong>：URL 里带 <code>#</code>，如 <code>/#/home</code>，后端只会看到 <code>/#</code> 前面的部分；刷新不会 404，部署最简单。</li><li><strong>history 模式</strong>：URL 更干净，如 <code>/home</code>，需要后端配合 <strong>把所有路径都返回同一个 <code>index.html</code></strong>，否则刷新会 404。</li></ul><p>对于面试官常问的“你们项目用的什么模式、为什么”，可以回答：</p><ul><li>管理后台项目一般会选 history 模式，URL 更好看，但需要 nginx 做 <code>try_files</code> 配置。</li><li>如果是纯静态托管环境、后端配合不好，hash 模式更省事。</li></ul>`,40)])])}const g=s(t,[["render",n]]);export{c as __pageData,g as default};
